mapper.insert:
INSERT INTO tb_draft_mst (
          draft_date
         ,seq
         ,draft_dept
         ,drafter
         ,client_name
         ,item_name
         ,order_qty
         ,due_date
         ,attach_file_id
         ,end_yn
         ,reg_id
         ,upd_id
)
VALUES (
        #{draftDate}
       ,#{seq}
       ,#{draftDept}
       ,#{drafter}
       ,#{clientName}
       ,#{itemName}
       ,#{orderQty}
       ,#{dueDate, jdbcType=DATE}
       ,#{attachFileId}
       ,'N'
       ,#{userId}
       ,#{userId}
       )

mapper.update:
UPDATE tb_draft_mst
SET    client_name    = #{clientName}
      ,item_name      = #{itemName}
      ,order_qty      = #{orderQty}
      ,due_date       = #{dueDate, jdbcType=DATE}
      ,upd_id         = #{userId}
      ,upd_dt         = GETDATE()
WHERE draft_id       = #{draftId}

